#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100005
#define INF 1000000000
typedef struct Edge {
    int u, v, c;
} Edge;
int compare(const void *a, const void *b) {
    Edge *e1 = (Edge *)a;
    Edge *e2 = (Edge *)b;
    return e1->u - e2->u;
}
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    Edge edges[M];
    for (int i = 0; i < M; i++) {
        scanf("%d %d %d", &edges[i].u, &edges[i].v, &edges[i].c);
    }
    qsort(edges, M, sizeof(Edge), compare);
    int s, t;
    scanf("%d %d", &s, &t);
    int dist[N + 1][N + 1];
    for (int i = 1; i <= N; i++) {
        for (int j = 1; j <= N; j++) {
            dist[i][j] = INF;
        }
    }
    dist[s][s] = 0;
    for (int i = 0; i < M; i++) {
        int u = edges[i].u;
        int v = edges[i].v;
        int c = edges[i].c;
        if (dist[s][u] != INF) {
            if (dist[s][v] == INF || dist[s][v] > dist[s][u] + (c != edges[i - 1].c)) {
                dist[s][v] = dist[s][u] + (c != edges[i - 1].c);
            }
        }
    }
    printf("%d\n", dist[s][t]);
    return 0;
}

